// Score Calc + Build Sheet Row (rewritten 2026-04-30).
// Email kommt jetzt direkt aus ctx._email (HTML Truncate Node) — Haiku liefert kein extracted_email mehr.
// notes-Feld bekommt "inhaber:Vorname Nachname" wenn Pattern hit, sonst leer.
const leadCtxAll = $('HTML Truncate + Merge Context').all();
const haikuAll = $input.all();

function parseHaikuJson(content) {
  if (!content || typeof content !== 'string') return null;
  let s = content.trim();
  s = s.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '').trim();
  try { return JSON.parse(s); } catch (e) { /* fallthrough */ }
  const m = s.match(/\{[\s\S]*\}/);
  if (m) { try { return JSON.parse(m[0]); } catch (e) { /* fallthrough */ } }
  return null;
}
function clamp(n, lo, hi) { return Math.max(lo, Math.min(hi, n)); }
function haikuErrorReason(haikuItem) {
  if (!haikuItem) return 'no_item';
  if (haikuItem.error) {
    const msg = (typeof haikuItem.error === 'string' ? haikuItem.error : (haikuItem.error.message || JSON.stringify(haikuItem.error)));
    return 'http_err:' + String(msg).slice(0, 40);
  }
  if (haikuItem.type === 'error' && haikuItem.error) {
    return 'api_err:' + String(haikuItem.error.type || haikuItem.error.message || 'unknown').slice(0, 40);
  }
  if (!haikuItem.content || !Array.isArray(haikuItem.content) || !haikuItem.content[0]) {
    return 'no_content';
  }
  const t = haikuItem.content[0].text;
  if (!t) return 'empty_text';
  return 'parse_fail:' + String(t).replace(/[\n\r\t]/g, ' ').slice(0, 40);
}

const out = [];
for (let i = 0; i < leadCtxAll.length; i++) {
  const ctx = leadCtxAll[i].json;
  const haikuItem = haikuAll[i] && haikuAll[i].json;
  let signals = null;
  let haikuError = false;
  let errReason = '';
  if (!haikuItem || haikuItem.error || haikuItem.type === 'error') {
    haikuError = true;
    errReason = haikuErrorReason(haikuItem);
  } else if (haikuItem.content && Array.isArray(haikuItem.content) && haikuItem.content[0] && haikuItem.content[0].text) {
    signals = parseHaikuJson(haikuItem.content[0].text);
    if (!signals) {
      haikuError = true;
      errReason = haikuErrorReason(haikuItem);
    }
  } else {
    haikuError = true;
    errReason = haikuErrorReason(haikuItem);
  }
  let score = 0;
  let summary = '';
  if (haikuError) {
    summary = ('HAIKU_ERR ' + errReason).slice(0, 80);
  } else {
    if (ctx._website_unreachable) {
      score += 30;
    } else {
      if (signals.no_ssl) score += 25;
      if (signals.mobile_broken) score += 20;
      if (signals.stale_copyright) {
        const yr = parseInt(String(signals.stale_copyright).match(/\d{4}/)?.[0] || '0', 10);
        if (yr && yr <= 2020) score += 15;
      }
      if (signals.generic_stock_look) score += 10;
      if (signals.load_time_slow) score += 10;
      if (signals.no_clear_cta) score += 8;
      if (signals.no_impressum_link) score += 6;
      if (signals.no_phone_in_header) score += 5;
      if (signals.no_meta_description) score += 3;
    }
    const rc = Number(ctx.review_count) || 0;
    if (rc < 10) score -= 10;
    if (rc > 100) score += 5;
    const gr = Number(ctx.google_rating) || 0;
    if (gr && gr < 3.5) score -= 15;
    score = clamp(score, 0, 100);
    summary = (signals.summary || '').slice(0, 80);
  }

  // Email + Inhaber kommen vom HTML-Truncate-Node (lokale Extraktion, keine Haiku-Abhängigkeit)
  const email = ctx._email || '';
  const notes = ctx._inhaber ? ('inhaber:' + ctx._inhaber) : '';

  out.push({
    json: {
      lead_id: ctx.lead_id,
      business_name: ctx.business_name,
      address: ctx.address,
      phone: ctx.phone,
      email: email,
      website_url: ctx.website_url,
      google_rating: ctx.google_rating != null ? ctx.google_rating : '',
      review_count: ctx.review_count != null ? ctx.review_count : '',
      score: score,
      signal_summary: summary,
      status: haikuError ? 'new' : 'scored',
      pitch_date: '',
      notes: notes
    }
  });
}
return out;

// Spec §5.5 Selektor-Logik.
const rows = $input.all().map(r => r.json).filter(r => r && r.lead_id);
const scored = rows.filter(r => String(r.status).trim() === 'scored');
scored.sort((a, b) => Number(b.score || 0) - Number(a.score || 0));
const top = scored.slice(0, 10);
// Aggregat-Counts
const countByStatus = (st) => rows.filter(r => String(r.status).trim() === st).length;
const summary = {
  total_scored: scored.length,
  total_pitched: countByStatus('pitched'),
  total_replied: countByStatus('replied'),
  total_won: countByStatus('won'),
  total_disqualified: countByStatus('disqualified'),
  max_score: top.length ? Number(top[0].score || 0) : 0,
  pipeline_empty: scored.length === 0,
  pipeline_thin: scored.length > 0 && scored.length < 10
};
// Single output item (briefing-stage erwartet aggregates)
return [{
  json: {
    leads: top,
    summary: summary,
    count: top.length
  }
}];

// Spec §5.5 Briefing-Template.
const input = $input.first().json;
const { leads, summary, count } = input;
const now = new Date();
const pad = n => String(n).padStart(2, '0');
const datum = now.getFullYear() + '-' + pad(now.getMonth()+1) + '-' + pad(now.getDate());
const runTs = datum + ' ' + pad(now.getHours()) + ':' + pad(now.getMinutes());
function slugify(s) {
  return String(s || '').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/ß/g, 'ss').replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue')
    .replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 32);
}
let md = '';
if (summary.pipeline_empty) {
  md = '# EMJmedia Leads — Briefing ' + datum + '\n\n' +
       '**Pipeline:** Leer. Alle gescorten Leads wurden gepitcht.\n\n' +
       '**Empfehlung:** Branche/Region rotieren (KFZ → Heizung, oder SH → andere Region) und neue Spec-Variante starten.\n';
} else {
  md += '# EMJmedia Leads — Briefing ' + datum + '\n\n';
  md += '**Pipeline-Status:** ' + summary.total_scored + ' ungepitchte Leads im Sheet · Top-Score heute: ' + summary.max_score;
  if (summary.pipeline_thin) md += ' · ⚠️ Pipeline wird dünn — neuer Run bald nötig';
  md += '\n\n---\n\n## Top ' + count + ' ungepitchte Leads (nach Score)\n\n';
  leads.forEach((lead, idx) => {
    const rank = idx + 1;
    const slug = slugify(lead.business_name);
    md += '### ' + rank + '. ' + lead.business_name + ' — Score ' + lead.score + '/100\n\n';
    md += '**Adresse:** ' + (lead.address || '—') + '  \n';
    md += '**Tel:** ' + (lead.phone || '—') + ' · **Mail:** ' + (lead.email || '—') + ' · **Web:** ' + (lead.website_url ? '[' + lead.website_url + '](' + lead.website_url + ')' : '—') + '  \n';
    md += '**Google:** ⭐ ' + (lead.google_rating || '—') + ' (' + (lead.review_count || 0) + ' Bewertungen)  \n';
    md += '**Signale:** `' + (lead.signal_summary || '—') + '`\n\n';
    md += '**Pitch-Vorbereitung:**\n';
    md += '- [ ] Demo-Site bauen: `kfz-' + slug + '.emj-media.de` (KFZ-Template kopieren, 5–8 Felder austauschen)\n';
    md += '- [ ] Mail aus `MAIL_TEMPLATE_KFZ_V1.md` mit Variablen befüllen\n';
    md += '- [ ] Versenden via Gmail (`info@emj-media.de`) → Sheet-Status auf `pitched`, Datum eintragen\n\n';
    md += '**Lead-ID:** `' + lead.lead_id + '` (für Sheet-Update)\n\n---\n\n';
  });
  md += '## Status-Schnellübersicht\n\n';
  md += '| Status | Anzahl |\n|--------|--------|\n';
  md += '| scored (offen) | ' + summary.total_scored + ' |\n';
  md += '| pitched | ' + summary.total_pitched + ' |\n';
  md += '| replied | ' + summary.total_replied + ' |\n';
  md += '| won | ' + summary.total_won + ' |\n';
  md += '| disqualified | ' + summary.total_disqualified + ' |\n\n';
  md += '---\n\n## Workflow-Run\n\n';
  md += '**Datum:** ' + runTs + '  \n';
  md += '**Workflow:** `leadhunter_kfz_sh`\n';
}
return [{
  json: {
    datum: datum,
    path: '/pulse/' + datum + '/EMJMEDIA_LEADS_BRIEFING.md',
    content: md
  }
}];
